import{_ as e,c as i,o as t,a2 as s}from"./chunks/framework.B7MVOZUf.js";const u=JSON.parse('{"title":"Git Base(git 基础知识和开发使用)","description":"","frontmatter":{},"headers":[],"relativePath":"src/Middleware/git/git-base.md","filePath":"src/Middleware/git/git-base.md","lastUpdated":1737139361000}'),n={name:"src/Middleware/git/git-base.md"};function l(r,a,p,o,d,c){return t(),i("div",null,a[0]||(a[0]=[s(`<h1 id="git-base-git-基础知识和开发使用" tabindex="-1">Git Base(git 基础知识和开发使用) <a class="header-anchor" href="#git-base-git-基础知识和开发使用" aria-label="Permalink to &quot;Git Base(git 基础知识和开发使用)&quot;">​</a></h1><h2 id="git-基础知识" tabindex="-1">Git 基础知识 <a class="header-anchor" href="#git-基础知识" aria-label="Permalink to &quot;Git 基础知识&quot;">​</a></h2><h3 id="git-简介" tabindex="-1">Git 简介 <a class="header-anchor" href="#git-简介" aria-label="Permalink to &quot;Git 简介&quot;">​</a></h3><p>Git 是目前最流行的版本控制系统，被誉为史上最优秀的版本控制系统。Git 是一个开源的分布式版本控制系统，可以有效、高速地处理从很小到非常大的项目版本管理。Git 与其它版本控制系统相比有以下几点不同：</p><ol><li>Git 是一个分布式版本控制系统，这意味着它可以克隆一个仓库到本地，然后在本地对仓库进行修改，而无需联网。</li><li>Git 是一个可靠的版本控制系统，它保证了完整性，确保了每一次提交的版本都是可用的。</li><li>Git 是一个开源的版本控制系统，这意味着任何人都可以免费使用 Git，并帮助开发者进行协作。</li><li>Git 是一个功能强大的版本控制系统，它支持多种工作流，包括集中式工作流、功能分支工作流、发布工作流等。</li><li>Git 是一个高效的版本控制系统，它在本地操作时速度快，在网络上进行版本控制时速度也快。</li></ol><h3 id="git-工作流" tabindex="-1">Git 工作流 <a class="header-anchor" href="#git-工作流" aria-label="Permalink to &quot;Git 工作流&quot;">​</a></h3><p>Git 工作流是 Git 最重要的概念之一。Git 工作流是指在日常开发中，使用 Git 进行代码版本控制的具体流程。Git 工作流有很多种，常用的有以下几种：</p><ol><li>集中式工作流：集中式工作流就是将代码库存放在中央服务器，开发者直接从中央服务器克隆代码到本地，然后在本地进行开发，开发完成后再将代码推送到中央服务器。集中式工作流是最简单的工作流，但是它不支持多人同时开发，也不支持分支开发。</li><li>功能分支工作流：功能分支工作流是将代码库存放在中央服务器，开发者克隆代码到本地，然后在本地创建分支进行开发，开发完成后再将分支合并到主分支。功能分支工作流支持多人同时开发，也支持分支开发。</li><li>发布工作流：发布工作流是将代码库存放在中央服务器，开发者克隆代码到本地，然后在本地进行开发，开发完成后将代码打包，然后发布到测试环境进行测试，测试通过后再发布到生产环境。发布工作流支持多人同时开发，也支持分支开发。</li><li>自定义工作流：自定义工作流是指根据实际情况，结合集中式、功能分支工作流和发布工作流的特点，制定一套适合自己的工作流。</li></ol><h3 id="git-基本命令" tabindex="-1">Git 基本命令 <a class="header-anchor" href="#git-基本命令" aria-label="Permalink to &quot;Git 基本命令&quot;">​</a></h3><p>Git 基本命令是 Git 最常用的命令。Git 基本命令有以下几种：</p><ol><li>git init：初始化一个 Git 仓库。</li><li>git add：添加文件到暂存区。</li><li>git commit：提交文件到本地仓库。</li><li>git clone：克隆一个远程仓库到本地。</li><li>git push：推送本地仓库的修改到远程仓库。</li><li>git pull：从远程仓库拉取最新代码到本地。</li><li>git branch：创建、切换、删除分支。</li><li>git checkout：切换分支。</li><li>git merge：合并分支。</li><li>git log：查看提交历史。</li><li>git status：查看仓库状态。</li></ol><h2 id="git-开发使用" tabindex="-1">Git 开发使用 <a class="header-anchor" href="#git-开发使用" aria-label="Permalink to &quot;Git 开发使用&quot;">​</a></h2><h3 id="git-安装" tabindex="-1">Git 安装 <a class="header-anchor" href="#git-安装" aria-label="Permalink to &quot;Git 安装&quot;">​</a></h3><p>Git 可以在各个平台上安装，包括 Windows、Mac、Linux 等。Git 安装非常简单，只需要到 Git 官方网站下载安装包，然后按照提示一步步安装就可以了。</p><h3 id="git-配置" tabindex="-1">Git 配置 <a class="header-anchor" href="#git-配置" aria-label="Permalink to &quot;Git 配置&quot;">​</a></h3><p>Git 的配置包括全局配置和本地配置。全局配置是针对用户的，而本地配置是针对仓库的。</p><h4 id="全局配置" tabindex="-1">全局配置 <a class="header-anchor" href="#全局配置" aria-label="Permalink to &quot;全局配置&quot;">​</a></h4><p>全局配置包括用户名和邮箱，以及 Git 的编辑器。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git config --global user.name &quot;your name&quot;</span></span>
<span class="line"><span>git config --global user.email &quot;your email&quot;</span></span>
<span class="line"><span>git config --global core.editor &quot;your editor&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h4 id="本地配置" tabindex="-1">本地配置 <a class="header-anchor" href="#本地配置" aria-label="Permalink to &quot;本地配置&quot;">​</a></h4><p>本地配置包括仓库的名称、描述、远程仓库地址等。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git config user.name &quot;your name&quot;</span></span>
<span class="line"><span>git config user.email &quot;your email&quot;</span></span>
<span class="line"><span>git config --local core.editor &quot;your editor&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="git-基本操作" tabindex="-1">Git 基本操作 <a class="header-anchor" href="#git-基本操作" aria-label="Permalink to &quot;Git 基本操作&quot;">​</a></h3><p>Git 的基本操作包括提交、拉取、推送、分支切换等。</p><h4 id="提交" tabindex="-1">提交 <a class="header-anchor" href="#提交" aria-label="Permalink to &quot;提交&quot;">​</a></h4><p>提交是 Git 最基本的操作，提交操作会将暂存区的文件提交到本地仓库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git commit -m &quot;commit message&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="拉取" tabindex="-1">拉取 <a class="header-anchor" href="#拉取" aria-label="Permalink to &quot;拉取&quot;">​</a></h4><p>拉取操作会从远程仓库拉取最新代码到本地。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git pull</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="推送" tabindex="-1">推送 <a class="header-anchor" href="#推送" aria-label="Permalink to &quot;推送&quot;">​</a></h4><p>推送操作会将本地仓库的修改推送到远程仓库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="分支切换" tabindex="-1">分支切换 <a class="header-anchor" href="#分支切换" aria-label="Permalink to &quot;分支切换&quot;">​</a></h4><p>分支切换操作会切换当前工作分支到指定分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git checkout branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="git-工作流-1" tabindex="-1">Git 工作流 <a class="header-anchor" href="#git-工作流-1" aria-label="Permalink to &quot;Git 工作流&quot;">​</a></h3><p>Git 工作流是指在日常开发中，使用 Git 进行代码版本控制的具体流程。Git 工作流有很多种，常用的有集中式工作流、功能分支工作流、发布工作流等。</p><h4 id="集中式工作流" tabindex="-1">集中式工作流 <a class="header-anchor" href="#集中式工作流" aria-label="Permalink to &quot;集中式工作流&quot;">​</a></h4><p>集中式工作流就是将代码库存放在中央服务器，开发者直接从中央服务器克隆代码到本地，然后在本地进行开发，开发完成后再将代码推送到中央服务器。集中式工作流是最简单的工作流，但是它不支持多人同时开发，也不支持分支开发。</p><h5 id="克隆代码" tabindex="-1">克隆代码 <a class="header-anchor" href="#克隆代码" aria-label="Permalink to &quot;克隆代码&quot;">​</a></h5><p>克隆代码操作会将远程仓库克隆到本地。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git clone https://github.com/username/repository.git</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="提交代码" tabindex="-1">提交代码 <a class="header-anchor" href="#提交代码" aria-label="Permalink to &quot;提交代码&quot;">​</a></h5><p>提交代码操作会将本地仓库的修改提交到本地仓库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git commit -m &quot;commit message&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="推送代码" tabindex="-1">推送代码 <a class="header-anchor" href="#推送代码" aria-label="Permalink to &quot;推送代码&quot;">​</a></h5><p>推送代码操作会将本地仓库的修改推送到远程仓库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git push</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="功能分支工作流" tabindex="-1">功能分支工作流 <a class="header-anchor" href="#功能分支工作流" aria-label="Permalink to &quot;功能分支工作流&quot;">​</a></h4><p>功能分支工作流是将代码库存放在中央服务器，开发者克隆代码到本地，然后在本地创建分支进行开发，开发完成后再将分支合并到主分支。功能分支工作流支持多人同时开发，也支持分支开发。</p><h5 id="创建分支" tabindex="-1">创建分支 <a class="header-anchor" href="#创建分支" aria-label="Permalink to &quot;创建分支&quot;">​</a></h5><p>创建分支操作会在本地创建一个新分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git branch branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="切换分支" tabindex="-1">切换分支 <a class="header-anchor" href="#切换分支" aria-label="Permalink to &quot;切换分支&quot;">​</a></h5><p>切换分支操作会切换当前工作分支到指定分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git checkout branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="提交代码-1" tabindex="-1">提交代码 <a class="header-anchor" href="#提交代码-1" aria-label="Permalink to &quot;提交代码&quot;">​</a></h5><p>提交代码操作会将本地仓库的修改提交到本地仓库。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git commit -m &quot;commit message&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="合并分支" tabindex="-1">合并分支 <a class="header-anchor" href="#合并分支" aria-label="Permalink to &quot;合并分支&quot;">​</a></h5><p>合并分支操作会将指定分支的代码合并到当前工作分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git merge branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h5 id="删除分支" tabindex="-1">删除分支 <a class="header-anchor" href="#删除分支" aria-label="Permalink to &quot;删除分支&quot;">​</a></h5><p>删除分支操作会删除指定分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git branch -d branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h4 id="发布工作流" tabindex="-1">发布工作流 <a class="header-anchor" href="#发布工作流" aria-label="Permalink to &quot;发布工作流&quot;">​</a></h4><p>发布工作流是将代码库存放在中央服务器，开发者克隆代码到本地，然后在本地进行开发，开发完成后将代码打包，然后发布到测试环境进行测试，测试通过后再发布到生产环境。发布工作流支持多人同时开发，也支持分支开发。</p><pre><code>1. 开发分支：开发分支是指开发人员在本地创建的分支，用于开发新功能或修复 bug。
</code></pre><ol start="2"><li><p>发布分支：发布分支是指测试人员在本地创建的分支，用于发布测试版本。</p></li><li><p>主分支：主分支是指代码库的主分支，是所有分支的最终汇总。</p></li><li><p>合并分支：合并分支操作会将指定分支的代码合并到当前工作分支。</p></li><li><p>打包发布：打包发布操作会将代码打包，并发布到测试环境进行测试。</p></li><li><p>发布测试：发布测试操作会将测试通过的代码发布到生产环境。</p><pre><code>##### 创建分支
</code></pre><p>创建分支操作会在本地创建一个新分支。</p></li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git branch branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><pre><code>##### 切换分支
</code></pre><p>切换分支操作会切换当前工作分支到指定分支。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>git checkout branch-name</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><pre><code>##### 提交代码
</code></pre><p>提交代码操作会将本地仓库的修改提交到本地仓库。</p><pre><code>\`\`\`
git commit -m &quot;commit message&quot;
\`\`\`

##### 合并分支
</code></pre><p>合并分支操作会将指定分支的代码合并到当前工作分支。</p><pre><code>\`\`\`
git merge branch-name
\`\`\`

##### 打包发布
</code></pre><p>打包发布操作会将代码打包，并发布到测试环境进行测试。</p><pre><code>\`\`\`
git checkout release
git merge develop
git tag v1.0.0
git push origin release --tags
\`\`\`

##### 发布测试
</code></pre><p>发布测试操作会将测试通过的代码发布到生产环境。</p><pre><code>\`\`\`
git checkout master
git merge release
git push origin master
\`\`\`

##### 回滚版本
</code></pre><p>回滚版本操作会将代码回滚到指定版本。</p><pre><code>\`\`\`
git reset --hard v1.0.0
\`\`\`
</code></pre><h3 id="git-常用命令" tabindex="-1">Git 常用命令 <a class="header-anchor" href="#git-常用命令" aria-label="Permalink to &quot;Git 常用命令&quot;">​</a></h3><p>Git 常用命令包括初始化、添加、提交、克隆、推送、拉取、分支切换、创建分支、切换分支、合并分支、删除分支、打包发布、发布测试、回滚版本等。</p><ol><li>初始化仓库：git init</li><li>添加文件到暂存区：git add file-name</li><li>提交文件到本地仓库：git commit -m &quot;commit message&quot;</li><li>克隆远程仓库到本地：git clone <a href="https://github.com/username/repository.git" target="_blank" rel="noreferrer">https://github.com/username/repository.git</a></li><li>推送本地仓库的修改到远程仓库：git push</li><li>从远程仓库拉取最新代码到本地：git pull</li><li>创建分支：git branch branch-name</li><li>切换分支：git checkout branch-name</li><li>合并分支：git merge branch-name</li><li>删除分支：git branch -d branch-name</li><li>打包发布：git checkout release &amp;&amp; git merge develop &amp;&amp; git tag v1.0.0 &amp;&amp; git push origin release --tags</li><li>发布测试：git checkout master &amp;&amp; git merge release &amp;&amp; git push origin master</li><li>回滚版本：git reset --hard v1.0.0</li></ol><h3 id="git-参考资料" tabindex="-1">Git 参考资料 <a class="header-anchor" href="#git-参考资料" aria-label="Permalink to &quot;Git 参考资料&quot;">​</a></h3><ul><li><a href="https://git-scm.com/doc" target="_blank" rel="noreferrer">Git 官方文档</a></li><li><a href="https://git-scm.com/doc/ext" target="_blank" rel="noreferrer">Git 官方教程</a></li><li><a href="https://git-scm.com/docs" target="_blank" rel="noreferrer">Git 官方帮助</a></li></ul>`,90)]))}const b=e(n,[["render",l]]);export{u as __pageData,b as default};
